#!/bin/bash

set -euo pipefail

SSHD_CONFIG="/etc/ssh/sshd_config"
SSHD_CONFIG_DIR="/etc/ssh/sshd_config.d"
SETTING="PermitRootLogin"
VALUE="no"

backup_config() {
    if [ ! -f "${SSHD_CONFIG}.bak" ]; then
        cp "${SSHD_CONFIG}" "${SSHD_CONFIG}.bak"
    fi
}

remove_conflicting_entries() {
    sed -i '/^[[:space:]]*PermitRootLogin[[:space:]]/d' "${SSHD_CONFIG}"

    if [ -d "${SSHD_CONFIG_DIR}" ]; then
        for conf_file in "${SSHD_CONFIG_DIR}"/*.conf; do
            [ -f "${conf_file}" ] || continue
            sed -i '/^[[:space:]]*PermitRootLogin[[:space:]]/d' "${conf_file}"
        done
    fi
}

add_setting() {
    if ! grep -q "^${SETTING}[[:space:]]" "${SSHD_CONFIG}"; then
        echo "${SETTING} ${VALUE}" >> "${SSHD_CONFIG}"
    fi
}

validate_config() {
    sshd -t
}

reload_sshd() {
    systemctl reload sshd
}

backup_config
remove_conflicting_entries
add_setting
validate_config
reload_sshd

#!/bin/bash

RULES_FILE="/etc/audit/rules.d/file-deletion.rules"
AUDIT_KEY="delete"
MIN_UID=$(awk '/^\s*UID_MIN/{print $2}' /etc/login.defs)
MIN_UID=${MIN_UID:-1000}

mkdir -p /etc/audit/rules.d

cat > "${RULES_FILE}" << EOF
## File deletion audit rules for renameat system call
-a always,exit -F arch=b64 -S renameat -F auid>=${MIN_UID} -F auid!=unset -k ${AUDIT_KEY}
-a always,exit -F arch=b32 -S renameat -F auid>=${MIN_UID} -F auid!=unset -k ${AUDIT_KEY}
-a always,exit -F arch=b64 -S renameat -F auid=0 -k ${AUDIT_KEY}
-a always,exit -F arch=b32 -S renameat -F auid=0 -k ${AUDIT_KEY}
EOF

augenrules --load

systemctl restart auditd 2>/dev/null || service auditd restart 2>/dev/null || true

